import React, { Component } from 'react'

export default class School extends Component {
    state = {
        types: []
    }

    componentDidMount() {
        let typesHtml = []
        for(const i of this.props.type) {
            typesHtml.push(<li>{i}</li>)
        }
        this.setState({ types: typesHtml })
    }

    render() {
        return (
            <div className="p-10 my-5 md:my-0 bg-white dark:bg-gray-800 dark:text-gray-50 md:w-2/5 md:mx-5 rounded shadow-2xl">
                <h2 className="uppercase text-2xl text-yellow-500 hover:text-primary dark:text-gray-400 dark:hover:text-secondaryDark font-mono italic" ><a href={this.props.url} target="_blank">// {this.props.school}</a></h2>
                <span className="text-blue-700 dark:text-blue-300 block mb-3 font-mono" >from({this.props.year.slice(0,4)},{this.props.year.slice(7,this.props.year.length)})</span>
                <ul className="list-disc list-inside">
                    {this.state.types}
                </ul>
            </div>
        )
    }
}
